# @title Importing Library
import numpy as np
import pandas as pd
import os
from sklearn.metrics import confusion_matrix, classification_report
import seaborn as sn
import matplotlib.pyplot as plt
import cv2
import tensorflow as tf
from tensorflow.keras.preprocessing.image import ImageDataGenerator

IMAGE_SIZE = (150,150)

# @title Image Data Generator
dataset_path = sriramr_fruits_fresh_and_rotten_for_classification_path
train_dir = os.path.join(dataset_path, 'dataset', 'train')
test_dir = os.path.join(dataset_path, 'dataset', 'test')
train_datagen = ImageDataGenerator(
    rescale=1.0 / 255,
    rotation_range=12,
    shear_range=0.15,
    zoom_range=0.2,
    horizontal_flip=True,
    fill_mode='nearest',
    validation_split=0.2)
# Create the training data generator
train_gen = train_datagen.flow_from_directory(
    train_dir,
    target_size=IMAGE_SIZE,
    batch_size=32,
    class_mode='categorical',
    subset='training',
    seed=42,
    shuffle=True
)
# Create the validation data generator
val_gen = train_datagen.flow_from_directory(
    train_dir,
    target_size=IMAGE_SIZE,
    batch_size=32,
    subset='validation',
    shuffle=False,
    seed=42
)

test_datagen = ImageDataGenerator(rescale=1.0 / 255)
test_gen = test_datagen.flow_from_directory(
    test_dir,
    target_size=IMAGE_SIZE,
    batch_size=32,
    class_mode='categorical',
    shuffle=False
)

# @title Collecting Training ,Testing Labels
from tqdm import tqdm

class_names = list(train_gen.class_indices.keys())  # This gets class names

train_labels = []
test_labels = []

# Iterate through the training generator to collect the labels
for _, labels in tqdm(train_gen, total=len(train_gen), desc="Collecting train labels"):
    train_labels.extend(labels)
    if len(train_labels) >= len(train_gen.filenames):
        break

# Iterate through the test generator to collect the labels
for _, labels in tqdm(test_gen, total=len(test_gen), desc="Collecting test labels"):
    test_labels.extend(labels)
    if len(test_labels) >= len(test_gen.filenames):
        break

# @title Visualization

import pandas as pd
train_labels = np.array(train_labels)
test_labels = np.array(test_labels)

train_counts = np.sum(train_labels, axis=0)
test_counts = np.sum(test_labels, axis=0)

# Create a DataFrame to visualize the counts for both train and test sets
df = pd.DataFrame({
    'train': train_counts,
    'test': test_counts
}, index=class_names)

# Plotting the counts using a bar chart
df.plot.bar()
