images, labels = next(train_gen)
labels = np.argmax(labels, axis=1)  # Convert one-hot encoded labels to integers
class_names = list(train_gen.class_indices.keys())

display_examples(class_names, images, labels)

# Display a batch of augmented images
def display_augmented_images(generator):
    # Get a batch of images and labels
    images, labels = next(generator)

    # Plot the first 16 images in the batch
    fig=plt.figure(figsize=(20,20))
    fig.suptitle("Some examples of images after augmented", fontsize=30)

    for i in range(16):
        plt.subplot(4,4, i + 1)
        plt.imshow(images[i])
        plt.axis('off')

    plt.show()

display_augmented_images(train_gen)

# @title Building a Model
from keras.models import Sequential
from keras.layers import Conv2D, MaxPooling2D, Input,Dropout, Flatten, Dense, Activation, BatchNormalization

model = Sequential()
model.add(Input(shape=(150, 150, 3)))
model.add(Conv2D(32, (3, 3), activation='relu'))
model.add(MaxPooling2D(pool_size=(2,2)))
#model.add(Dropout(0.25))
model.add(Conv2D(64, (3, 3), activation='relu'))
model.add(MaxPooling2D(pool_size=(2, 2)))
model.add(Conv2D(128, (3, 3), activation='relu'))
model.add(MaxPooling2D(pool_size=(2, 2)))
model.add(Flatten())
model.add(Dense(128, activation='relu',))
#model.add(Dense(32, activation='relu'))
model.add(Dense(6, activation='softmax'))
model.compile(loss='categorical_crossentropy', optimizer='adam', metrics=['accuracy'])
model.summary()

# @title Learning Rate and Early Stopping
from keras.callbacks import EarlyStopping, ReduceLROnPlateau
earlystop = EarlyStopping(patience=5)
learning_rate_reduction = ReduceLROnPlateau(monitor='val_accuracy',
                                            patience=2,
                                            verbose=1,
                                            factor=0.5,
                                            min_lr=0.00001)
callbacks = [earlystop, learning_rate_reduction]

# @title Fit Model
epochs=12
history = model.fit(
    train_gen,
    validation_data=val_gen,
    epochs=epochs,
    callbacks=callbacks
)

# @title Plot accuracy & loss function
def plot_accuracy_loss(history):
    """
        Plot the accuracy and the loss during the training of the nn.
    """
    fig = plt.figure(figsize=(25,15))

    # Plot accuracy
    plt.subplot(221)
    plt.plot(history.history['accuracy'],'bo--', label = "acc")
    plt.plot(history.history['val_accuracy'], 'ro--', label = "val_acc")
    plt.title("train_acc vs val_acc")
    plt.ylabel("accuracy")
    plt.xlabel("epochs")
    plt.legend()

    # Plot loss function
    plt.subplot(222)
    plt.plot(history.history['loss'],'bo--', label = "loss")
    plt.plot(history.history['val_loss'], 'ro--', label = "val_loss")
    plt.title("train_loss vs val_loss")
    plt.ylabel("loss")
    plt.xlabel("epochs")

    plt.legend()
    plt.show()
plot_accuracy_loss(history)

# @title Test Accuracy
loss, accuracy = model.evaluate(test_gen)
print(f'Test Accuracy: {accuracy * 100:.2f}%')

# @title Confusion Matrix & Classification report
import numpy as np
import matplotlib.pyplot as plt
from sklearn.metrics import confusion_matrix, classification_report, ConfusionMatrixDisplay
from tensorflow.keras.models import load_model
from tensorflow.keras.preprocessing.image import ImageDataGenerator

y_pred = model.predict(test_gen)

# Convert to class labels
y_pred_classes = np.argmax(y_pred, axis=1)
y_test = test_gen.classes
class_names = list(test_gen.class_indices.keys())

# Compute confusion matrix
cm = confusion_matrix(y_test, y_pred_classes)

# Display confusion matrix
disp = ConfusionMatrixDisplay(confusion_matrix=cm, display_labels=class_names)
disp.plot(cmap=plt.cm.Blues, xticks_rotation='vertical')
plt.title("Confusion Matrix")
plt.show()

# Classification report
print("\nClassification Report:")
print(classification_report(y_test, y_pred_classes, target_names=class_names))

