import numpy as np
import matplotlib.pyplot as plt

def display_random_image(class_names, images, predictions):
    """
    Display a random image from the images array and its corresponding predicted label.
    """
    index = np.random.randint(images.shape[0])

    # Display the image
    plt.figure()
    plt.imshow(images[index])
    plt.xticks([])  # Hide the x-axis ticks
    plt.yticks([])  # Hide the y-axis ticks
    plt.grid(False)
    predicted_label = class_names[np.argmax(predictions[index])]

    plt.title(f'Image #{index}: {predicted_label}')
    plt.show()

# Get a batch of data from the test generator
test_images, test_labels = next(test_gen)

predictions = model.predict(test_images)

# Display a random image with its predicted label
display_random_image(class_names, test_images, predictions)

